const t=`{% block sw_promotion_v2_settings_rule_selection %} <div class="sw-promotion-v2-settings-rule-selection"> {% block sw_promotion_v2_settings_rule_selection_description %} <sw-promotion-v2-wizard-description class="sw-promotion-v2-settings-rule-selection__description"> {{ $t('sw-promotion-v2.detail.discounts.settings.ruleSelection.description') }} </sw-promotion-v2-wizard-description> {% endblock %} {% block sw_promotion_v2_settings_rule_selection_selection %} <sw-select-rule-create v-model:rules="discount.discountRules" :rule-filter="ruleCriteria" :rule-scope="['cart']" local-mode :label="$t('sw-promotion-v2.detail.discounts.settings.ruleSelection.labelSelection')" :placeholder="$t('sw-promotion-v2.detail.discounts.settings.ruleSelection.placeholderSelection')" :disabled="!acl.can('promotion.editor')" /> {% endblock %} </div> {% endblock %}`,{Criteria:e}=Shopware.Data,o={template:t,inject:["acl"],props:{discount:{type:Object,required:!0}},computed:{ruleCriteria(){return new e(1,25).addSorting(e.sort("name","ASC",!1))}}};export{o as default};
